1	/**
2	 * resolveRouteFromSettings() — DRY helper for workers and the chat route.
3	 *
4	 * Reads both the role's model setting (default_${role}_route) AND the role's
5	 * reasoning-effort setting (default_${role}_reasoning_effort) in one query,
6	 * then hands the pair to resolveModelRoute() so the returned OracleModelRoute
7	 * already has `reasoningEffort` attached.
8	 *
9	 * Returns null when the model setting is unset or unparseable — callers should
10	 * fall back to a hardcoded route (typically the curated catalog primary for
11	 * the role).
12	 */
13	
14	import { inArray } from 'drizzle-orm';
15	import type { OracleDb } from '@oracle/db';
16	import { settings } from '@oracle/db/schema';
17	import { ROUTE_SETTING_KEYS, REASONING_EFFORT_SETTING_KEYS } from './defaults';
18	import { resolveModelRoute } from './resolve';
19	import type { OracleModelRole, OracleModelRoute, ReasoningEffort } from './types';
20	
21	function isReasoningEffort(v: unknown): v is ReasoningEffort {
22	  return v === 'off' || v === 'low' || v === 'medium' || v === 'high';
23	}
24	
25	export async function resolveRouteFromSettings(
26	  db: OracleDb,
27	  role: OracleModelRole,
28	): Promise<OracleModelRoute | null> {
29	  const routeKey = ROUTE_SETTING_KEYS[role];
30	  const effortKey = REASONING_EFFORT_SETTING_KEYS[role];
31	
32	  const rows = await db
33	    .select({ key: settings.key, value: settings.value })
34	    .from(settings)
35	    .where(inArray(settings.key, [routeKey, effortKey]));
36	
37	  const routeRow = rows.find((r) => r.key === routeKey);
38	  const effortRow = rows.find((r) => r.key === effortKey);
39	
40	  const modelIdOrRouteId =
41	    typeof routeRow?.value === 'string' ? routeRow.value : null;
42	  if (!modelIdOrRouteId) return null;
43	
44	  const effort: ReasoningEffort | undefined = isReasoningEffort(effortRow?.value)
45	    ? effortRow.value
46	    : undefined;
47	
48	  return resolveModelRoute(modelIdOrRouteId, role, effort);
49	}
