55	function fmtPrice(n: number): string {
56	  if (n === 0) return '0';
57	  if (n < 0.001) return n.toFixed(5);
58	  if (n < 0.1) return n.toFixed(3);
59	  return n.toFixed(2);
60	}
61	
62	function fmtCtx(n: number): string {
63	  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(n % 1_000_000 === 0 ? 0 : 1)}M`;
64	  if (n >= 1_000) return `${Math.round(n / 1_000)}K`;
65	  return n.toLocaleString();
66	}
67	
68	function priceBadge(m: Model): string | null {
69	  if (m.promptPer1M == null) return null;
70	  if (m.promptPer1M === 0 && (m.completionPer1M ?? 0) === 0) return 'Free';
71	  return `$${fmtPrice(m.promptPer1M)} / $${fmtPrice(m.completionPer1M ?? 0)}`;
72	}
73	
74	/** Derive stage from a settings key like 'default_interview_route'. */
75	function stageFromKey(settingKey: string): Stage | 'general' {
76	  if (settingKey.includes('general_purpose')) return 'general';
77	  if (settingKey.includes('interview')) return 'interview';
78	  if (settingKey.includes('extraction')) return 'extraction';
79	  if (settingKey.includes('synthesis')) return 'synthesis';
80	  return 'interview';
81	}
