111	            {cap.short}
112	          </span>
113	        ))}
114	        <span className="flex items-center gap-1 text-xs text-muted-foreground" title="Cost per 1 million input / output tokens">
115	          <span className="font-mono text-[10px] text-muted-foreground">$/M</span>
116	          Price per 1M tokens (in&nbsp;/&nbsp;out)
117	        </span>
118	      </div>
119	    </div>
120	  );
121	}
