127	export function ModelPicker({
128	  currentModel,
129	  currentEffort,
130	  settingKey,
131	  settingDescription,
132	  effortSettingKey,
133	  effortSettingDescription,
134	}: {
135	  currentModel: string | null;
136	  currentEffort: ReasoningEffort | null;
137	  settingKey: string;
138	  settingDescription: string;
139	  /** Settings key for the reasoning-effort dropdown. Optional —
140	   *  if omitted, the effort selector is hidden entirely (e.g. for general-purpose
141	   *  picker where there's no stage to associate effort with). */
142	  effortSettingKey?: string;
143	  effortSettingDescription?: string;
144	}) {
145	  const [models, setModels] = useState<Model[]>([]);
146	  const [loading, setLoading] = useState(true);
147	  const [fetchError, setFetchError] = useState<string | null>(null);
148	  const [selected, setSelected] = useState<string>(
149	    currentModel ?? 'anthropic/claude-sonnet-4.6',
150	  );
151	  const [effort, setEffort] = useState<ReasoningEffort>(currentEffort ?? 'medium');
152	  const [status, setStatus] = useState<Status>('idle');
153	  const [saveError, setSaveError] = useState<string | null>(null);
154	
155	  // Dropdown open state + search filter.
156	  const [open, setOpen] = useState(false);
157	  const [query, setQuery] = useState('');
158	  const dropdownRef = useRef<HTMLDivElement>(null);
159	  const searchRef = useRef<HTMLInputElement>(null);
160	
161	  const stageOrGeneral = stageFromKey(settingKey);
162	
163	  useEffect(() => {
164	    let cancelled = false;
165	    async function loadModels() {
166	      try {
167	        const res = await fetch(`/api/admin/models?stage=${stageOrGeneral}`);
168	        if (!res.ok) {
169	          const body = await res.text();
170	          throw new Error(`${res.status}: ${body}`);
171	        }
172	        const data = (await res.json()) as { models: Model[] };
173	        if (!cancelled) {
174	          setModels(data.models);
175	          if (currentModel && data.models.some((m) => m.id === currentModel)) {
176	            setSelected(currentModel);
177	          }
178	        }
179	      } catch (err) {
180	        if (!cancelled) {
181	          setFetchError(err instanceof Error ? err.message : String(err));
182	        }
183	      } finally {
184	        if (!cancelled) setLoading(false);
185	      }
186	    }
187	    void loadModels();
188	    return () => { cancelled = true; };
189	  }, [currentModel, stageOrGeneral]);
190	
191	  // Close on outside click.
192	  useEffect(() => {
193	    function handler(e: MouseEvent) {
194	      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
195	        setOpen(false);
196	        setQuery('');
197	      }
198	    }
199	    document.addEventListener('mousedown', handler);
200	    return () => document.removeEventListener('mousedown', handler);
201	  }, []);
202	
203	  // Focus search when dropdown opens.
204	  useEffect(() => {
205	    if (open) {
206	      setTimeout(() => searchRef.current?.focus(), 0);
207	    }
208	  }, [open]);
209	
210	  async function save() {
211	    setStatus('saving');
212	    setSaveError(null);
213	    try {
214	      // Save model selection.
215	      const res = await fetch('/api/admin/settings', {
216	        method: 'POST',
217	        headers: { 'Content-Type': 'application/json' },
218	        body: JSON.stringify({
219	          key: settingKey,
220	          value: selected,
221	          description: settingDescription,
222	        }),
223	      });
224	      if (!res.ok) throw new Error(`${res.status}: ${await res.text()}`);
225	
226	      // Save effort selection if applicable (and the selected model supports reasoning).
227	      if (effortSettingKey && selectedModel?.thinking) {
228	        const r2 = await fetch('/api/admin/settings', {
229	          method: 'POST',
230	          headers: { 'Content-Type': 'application/json' },
231	          body: JSON.stringify({
232	            key: effortSettingKey,
233	            value: effort,
234	            description: effortSettingDescription ?? `Reasoning effort for ${settingKey}.`,
235	          }),
236	        });
237	        if (!r2.ok) throw new Error(`${r2.status}: ${await r2.text()}`);
238	      }
239	
240	      setStatus('saved');
241	      setTimeout(() => setStatus('idle'), 3000);
242	    } catch (err) {
243	      setSaveError(err instanceof Error ? err.message : String(err));
244	      setStatus('error');
245	    }
246	  }
247	
248	  const selectedModel = models.find((m) => m.id === selected);
249	
250	  // Filter the dropdown using the same predicates as the model-pool page.
251	  // For the "general" picker (no stage), don't filter — show all models.
252	  const compatible = (
253	    stageOrGeneral === 'general'
254	      ? models
255	      : models.filter((m) => meetsStageReq(m, stageOrGeneral))
256	  ).sort((a, b) => (a.promptPer1M ?? Infinity) - (b.promptPer1M ?? Infinity));
257	
258	  const filtered = query.trim()
259	    ? compatible.filter(
260	        (m) =>
261	          m.id.toLowerCase().includes(query.toLowerCase()) ||
262	          m.name.toLowerCase().includes(query.toLowerCase()),
263	      )
264	    : compatible;
265	
266	  if (loading) {
267	    return <p className="text-sm text-muted-foreground">Loading available models…</p>;
268	  }
269	  if (fetchError) {
270	    return <p className="text-sm text-destructive">Failed to load models: {fetchError}</p>;
271	  }
272	
273	  // For stage pickers, find which requirements the *selected* model fails.
274	  // We use this to surface a small warning under the dropdown when an admin
275	  // somehow has a non-compliant model saved (e.g., from before stage reqs changed).
276	  const selectedMissing = selectedModel && stageOrGeneral !== 'general'
277	    ? missingReqs(selectedModel, stageOrGeneral)
278	    : [];
279	
280	  const effortApplicable = effortSettingKey && selectedModel?.thinking === true;
281	
282	  return (
283	    <div className="space-y-4">
284	
285	      {/* ── Model + effort dropdowns (side by side when effort is applicable) ─ */}
286	      <div className="space-y-2">
287	        <label className="text-sm font-medium leading-none">Model</label>
288	
289	        <div className="flex items-start gap-2">
290	          {/* Model dropdown */}
291	          <div className="relative flex-1 min-w-0" ref={dropdownRef}>
292	            <button
293	              type="button"
294	              onClick={() => { setOpen((v) => !v); }}
295	              disabled={status === 'saving'}
296	              className={cn(
297	                'w-full flex items-center justify-between gap-2 rounded-md border border-input bg-background px-3 py-2 text-sm',
298	                'ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2',
299	                'disabled:cursor-not-allowed disabled:opacity-50',
300	              )}
301	            >
302	              <span className="flex items-center gap-2 min-w-0">
303	                <span className="font-mono truncate">
304	                  {selected || 'Select a model…'}
305	                </span>
306	                {selectedModel && <CapIcons model={selectedModel} />}
307	              </span>
308	              <ChevronDown className={cn('size-4 shrink-0 text-muted-foreground transition-transform', open && 'rotate-180')} />
309	            </button>
310	
311	            {/* Floating list */}
312	            {open && (
313	              <div className="absolute z-50 mt-1 w-full rounded-md border bg-background shadow-lg">
314	                <div className="flex items-center gap-2 border-b px-3 py-2">
315	                  <Search className="size-3.5 shrink-0 text-muted-foreground" />
316	                  <input
317	                    ref={searchRef}
318	                    type="text"
319	                    placeholder="Search models…"
320	                    value={query}
321	                    onChange={(e) => setQuery(e.target.value)}
322	                    className="w-full bg-transparent text-sm outline-none placeholder:text-muted-foreground"
323	                  />
324	                </div>
325	                <ul className="max-h-72 overflow-y-auto py-1" role="listbox">
326	                  {filtered.length === 0 && (
327	                    <li className="px-3 py-4 text-center text-sm text-muted-foreground">
328	                      No models match &ldquo;{query}&rdquo;
329	                    </li>
330	                  )}
331	                  {filtered.map((m) => {
332	                    const badge = priceBadge(m);
333	                    const isSelected = m.id === selected;
334	                    return (
335	                      <li key={m.id} role="option" aria-selected={isSelected}>
336	                        <button
337	                          type="button"
338	                          onClick={() => {
339	                            setSelected(m.id);
340	                            setStatus('idle');
341	                            setOpen(false);
342	                            setQuery('');
343	                          }}
344	                          className={cn(
345	                            'w-full flex items-center justify-between gap-2 px-3 py-2 text-left text-sm hover:bg-muted',
346	                            isSelected && 'bg-muted/60',
347	                          )}
348	                        >
349	                          <span className="flex items-center gap-1.5 min-w-0">
350	                            <Check
351	                              className={cn(
352	                                'size-3.5 shrink-0',
353	                                isSelected ? 'text-foreground' : 'invisible',
354	                              )}
355	                            />
356	                            <span className="font-mono text-xs truncate">{m.id}</span>
357	                            <CapIcons model={m} size={3} />
358	                          </span>
359	                          {badge != null && (
360	                            <span
361	                              className={cn(
362	                                'shrink-0 rounded px-1.5 py-0.5 font-mono text-[10px]',
363	                                badge === 'Free'
364	                                  ? 'bg-emerald-50 text-emerald-700'
365	                                  : 'bg-muted text-muted-foreground',
366	                              )}
367	                            >
368	                              {badge}
369	                            </span>
370	                          )}
371	                        </button>
372	                      </li>
373	                    );
374	                  })}
375	                </ul>
376	
377	                <div className="border-t px-3 py-1.5 text-[10px] text-muted-foreground">
378	                  {filtered.length} of {compatible.length} compatible models
379	                </div>
380	              </div>
381	            )}
382	          </div>
383	
384	          {/* Effort dropdown (only when this is a stage picker AND selected model supports reasoning) */}
385	          {effortApplicable && (
386	            <div className="w-32 shrink-0">
387	              <select
388	                value={effort}
389	                onChange={(e) => { setEffort(e.target.value as ReasoningEffort); setStatus('idle'); }}
390	                title="Reasoning effort — translated per-provider (Anthropic budget_tokens, OpenAI reasoning_effort, Vertex thinkingBudget)"
391	                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm
392	                           ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
393	              >
394	                {EFFORT_OPTIONS.map((opt) => (
395	                  <option key={opt.value} value={opt.value}>
396	                    Effort: {opt.label}
397	                  </option>
398	                ))}
399	              </select>
400	            </div>
401	          )}
402	        </div>
403	
404	        {/* Warning if the saved model fails the stage's current requirements */}
405	        {selectedMissing.length > 0 && (
406	          <p className="text-xs text-amber-600 dark:text-amber-400">
407	            ⚠ Selected model doesn&apos;t meet this stage&apos;s requirements:{' '}
408	            {selectedMissing.map((r) => r.label).join(', ')}
409	          </p>
410	        )}
411	      </div>
412	
413	      {/* ── Selected model detail card ────────────────────────────────────── */}
414	      {selectedModel && (
415	        <div className="rounded-md border bg-muted/30 px-4 py-3 text-xs space-y-1.5">
416	          <p className="font-medium text-sm text-foreground">{selectedModel.name}</p>
417	
418	          <div className="flex flex-wrap gap-x-4 gap-y-1 text-muted-foreground">
419	            {selectedModel.contextLength != null && (
420	              <span>Context: {fmtCtx(selectedModel.contextLength)} tokens</span>
421	            )}
422	            {selectedModel.promptPer1M != null && (
423	              <span>
424	                {selectedModel.promptPer1M === 0 && (selectedModel.completionPer1M ?? 0) === 0
425	                  ? 'Free'
426	                  : `$${fmtPrice(selectedModel.promptPer1M)} in / $${fmtPrice(selectedModel.completionPer1M ?? 0)} out per 1M tokens`
427	                }
428	              </span>
429	            )}
430	          </div>
431	
432	          {/* Active capabilities */}
433	          {CAPS.some((c) => (selectedModel as unknown as Record<CapKey, boolean>)[c.field]) && (
434	            <div className="flex flex-wrap gap-2 pt-0.5">
435	              {CAPS.filter((c) => (selectedModel as unknown as Record<CapKey, boolean>)[c.field]).map((cap) => (
436	                <span
437	                  key={cap.field}
438	                  title={cap.long}
439	                  className="flex items-center gap-1 text-xs text-muted-foreground"
440	                >
441	                  <cap.icon className={cn('size-3', cap.color)} />
442	                  {cap.short}
443	                </span>
444	              ))}
445	            </div>
446	          )}
447	        </div>
448	      )}
449	
450	      {/* ── Save button ───────────────────────────────────────────────────── */}
451	      <div className="flex items-center gap-3">
452	        <Button onClick={save} disabled={status === 'saving'} size="sm">
453	          {status === 'saving' ? 'Saving…' : effortApplicable ? 'Save model + effort' : 'Save model'}
454	        </Button>
455	        {status === 'saved' && (
456	          <span className="text-sm text-green-600">Saved.</span>
457	        )}
458	        {status === 'error' && saveError && (
459	          <span className="text-sm text-destructive">{saveError}</span>
460	        )}
461	      </div>
462	
463	      {currentModel && currentModel !== selected && status === 'idle' && (
464	        <p className="text-xs text-muted-foreground">
465	          Active model: <code className="font-mono">{currentModel}</code>
466	        </p>
467	      )}
468	
469	      {/* ── Icon legend ───────────────────────────────────────────────────── */}
470	      <Legend />
471	    </div>
472	  );
473	}
