1	// GET  /api/admin/settings          — read all settings rows
2	// POST /api/admin/settings          — upsert a single setting by key
3	//
4	// Both endpoints require admin.
5	
6	import { NextResponse, type NextRequest } from 'next/server';
7	import { eq } from 'drizzle-orm';
8	import { z } from 'zod';
9	import { requireAdmin } from '@/lib/auth-guard';
10	import { getDirectDb } from '@oracle/db/client';
11	import { settings } from '@oracle/db/schema';
12	
13	export const dynamic = 'force-dynamic';
14	
15	export async function GET() {
16	  try {
17	    await requireAdmin();
18	  } catch {
19	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
20	  }
21	
22	  const db = getDirectDb();
23	  const rows = await db.select().from(settings).orderBy(settings.key);
24	  return NextResponse.json({ settings: rows });
25	}
26	
27	const UpsertSchema = z.object({
28	  key: z.string().min(1).max(100),
29	  value: z.unknown(),
30	  description: z.string().optional(),
31	});
32	
33	export async function POST(req: NextRequest) {
34	  try {
35	    await requireAdmin();
36	  } catch {
37	    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
38	  }
39	
40	  let body: z.infer<typeof UpsertSchema>;
41	  try {
42	    body = UpsertSchema.parse(await req.json());
43	  } catch (err) {
44	    return NextResponse.json(
45	      { error: 'Invalid request body', detail: String(err) },
46	      { status: 400 },
47	    );
48	  }
49	
50	  const db = getDirectDb();
51	  const [row] = await db
52	    .insert(settings)
53	    .values({
54	      key: body.key,
55	      value: body.value,
56	      ...(body.description !== undefined ? { description: body.description } : {}),
57	    })
58	    .onConflictDoUpdate({
59	      target: settings.key,
60	      set: {
61	        value: body.value,
62	        updatedAt: new Date(),
63	        ...(body.description !== undefined
64	          ? { description: body.description }
65	          : {}),
66	      },
67	    })
